// Calcola minuti escludendo pausa pranzo
const calcMinutesExcludingLunch = (fromStr, toStr) => {
  const toMins = (t) => { const [h, m] = t.split(':').map(Number); return h * 60 + m; };
  const from = toMins(fromStr);
  const to = toMins(toStr);
  const lunchS = toMins(LUNCH_START);
  const lunchE = toMins(LUNCH_END);
  if (to <= from) return 0;
  let total = to - from;
  const overlapStart = Math.max(from, lunchS);
  const overlapEnd = Math.min(to, lunchE);
  if (overlapEnd > overlapStart) total -= (overlapEnd - overlapStart);
  return Math.max(0, total);
};

const getISOWeek = (date) => {
  const d = new Date(date);
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + 3 - (d.getDay() + 6) % 7);
  const week1 = new Date(d.getFullYear(), 0, 4);
  return 1 + Math.round(((d - week1) / 86400000 - 3 + (week1.getDay() + 6) % 7) / 7);
};

const formatMinutes = (mins) => {
  const h = Math.floor(mins / 60);
  const m = mins % 60;
  return h > 0 ? `${h}h ${m > 0 ? m + 'min' : ''}`.trim() : `${m}min`;
};

const formatDate = (isoStr) => {
  if (!isoStr) return '';
  const [y, m, d] = isoStr.split('-');
  return d + '/' + m + '/' + y;
};

// ─── Helpers suddivisione temporale ───────────────────────────────────────
const getWeekBounds = () => {
  const now = new Date();
  const day = now.getDay(); // 0=Dom
  const diffToMon = day === 0 ? -6 : 1 - day;
  const mon = new Date(now); mon.setDate(now.getDate() + diffToMon); mon.setHours(0,0,0,0);
  const sat = new Date(mon); sat.setDate(mon.getDate() + 5); sat.setHours(23,59,59,999);
  return { mon, sat };
};

const classifyByTime = (items, getDateFn) => {
  const { mon, sat } = getWeekBounds();
  const now = new Date();
  const thirtyDaysAgo = new Date(now); thirtyDaysAgo.setDate(now.getDate() - 30);
  const thisWeek = [], lastThirty = [], older = [];
  for (const item of items) {
    const d = new Date(getDateFn(item));
    if (d >= mon && d <= sat) thisWeek.push(item);
    else if (d >= thirtyDaysAgo) lastThirty.push(item);
    else older.push(item);
  }
  return { thisWeek, lastThirty, older };
};

